# -*- coding: utf-8 -*-
import json

NEW_INTRO = {
"131": "Основные понятия: Равновесное тепловое излучение — это электромагнитное излучение, испускаемое любым нагретым телом за счёт теплового движения его атомов и молекул, находящееся в термодинамическом равновесии с самим телом: тело поглощает столько же энергии излучения, сколько и испускает, поэтому спектральный состав и интенсивность такого излучения зависят только от температуры тела и не зависят от его формы, размера или химического состава (для идеализированной модели абсолютно чёрного тела). Тепловое излучение — единственный вид излучения, который может находиться в термодинамическом равновесии с веществом, и оно есть у любого тела с температурой выше абсолютного нуля, что лежит в основе многих методов бесконтактного измерения температуры (термография, пирометрия).",
"132": "Основные понятия: Законы теплового излучения количественно описывают, как интенсивность и спектральный состав излучения нагретого тела зависят от его температуры: с ростом температуры суммарная энергия, излучаемая телом, резко (пропорционально четвёртой степени температуры) возрастает, а максимум спектра излучения смещается в сторону более коротких волн (от инфракрасного к видимому и далее). Термография — это медицинский и технический метод, основанный на регистрации инфракрасного теплового излучения, испускаемого поверхностью тела (или объекта), и построении на его основе температурной карты (термограммы) без какого-либо контакта или облучения объекта; в медицине термография позволяет неинвазивно выявлять участки с аномальной температурой, связанные с воспалительными процессами, нарушением кровообращения или опухолевым ростом.",
"133": "Основные понятия: Квант излучения — это минимальная неделимая порция электромагнитного излучения (энергии), которой обмениваются вещество и электромагнитное поле; открытие квантования энергии излучения (Планком) стало основой всей квантовой физики, показав, что энергия испускается и поглощается не непрерывно, а дискретными порциями. Энергия одного кванта (фотона) прямо пропорциональна частоте излучения — чем выше частота (короче длина волны), тем больше энергия каждого отдельного кванта, поэтому, например, кванты рентгеновского или гамма-излучения обладают значительно большей энергией, чем кванты видимого света или радиоволн, что и определяет их разное биологическое действие.",
"134": "Основные понятия: Фотоэффект — это явление испускания электронов веществом (чаще всего металлом) под действием падающего на него электромагнитного излучения (света); фотоэффект стал одним из ключевых экспериментальных доказательств квантовой (корпускулярной) природы света, поскольку его закономерности невозможно объяснить с точки зрения чисто волновой теории света. Уравнение фотоэффекта (уравнение Эйнштейна) выражает закон сохранения энергии для этого процесса: энергия поглощённого электроном кванта света расходуется на совершение работы выхода электрона из вещества (преодоление сил, удерживающих электрон в металле) и на сообщение вылетевшему электрону кинетической энергии. Из уравнения следует существование красной границы фотоэффекта — минимальной частоты света, ниже которой фотоэффект вообще не возникает, независимо от интенсивности излучения, поскольку энергии одного кванта недостаточно даже для совершения работы выхода.",
"135": "Основные понятия: Корпускулярно-волновой дуализм — это фундаментальное свойство микрообъектов (света, электронов и других частиц) проявлять себя в одних экспериментах как волна (демонстрируя интерференцию, дифракцию), а в других — как частица (демонстрируя дискретные, локализованные взаимодействия, как при фотоэффекте или столкновениях). Это не означает, что микрообъект «одновременно и волна, и частица» в привычном классическом смысле — скорее, ни волновая, ни корпускулярная модель по отдельности не описывают полностью поведение микрообъекта, и то, какие свойства проявятся, зависит от условий конкретного эксперимента. Корпускулярно-волновой дуализм — один из центральных принципов, отличающих квантовую физику от классической и требующих принципиально нового математического аппарата (квантовой механики) для описания микромира.",
"136": "Основные понятия: Гипотеза де Бройля обобщила идею корпускулярно-волновой природы света на все материальные частицы (электроны, протоны и даже макроскопические тела), предположив, что с любой движущейся частицей связана волна, длина которой обратно пропорциональна импульсу частицы — чем больше импульс (масса и скорость) частицы, тем короче соответствующая ей волна де Бройля. Для макроскопических тел (массой в граммы и более) длина волны де Бройля настолько ничтожно мала, что волновые свойства практически не проявляются и незаметны на опыте, тогда как для микрочастиц (электронов) длина волны де Бройля сопоставима с размерами атомов, поэтому волновые эффекты (например, дифракция электронов) экспериментально наблюдаемы и практически значимы (используются, в частности, в электронной микроскопии).",
"137": "Основные понятия: Соотношение неопределённостей Гейзенберга — фундаментальный принцип квантовой механики, утверждающий, что для микрочастицы невозможно одновременно точно (со сколь угодно малой неопределённостью) знать значения некоторых пар физических величин, например координату и импульс частицы: чем точнее определена координата частицы, тем более неопределённым (размытым) оказывается её импульс, и наоборот. Это ограничение носит принципиальный, фундаментальный характер — оно не связано с несовершенством измерительных приборов, а отражает саму природу микрообъектов, которые нельзя описывать как классические частицы с одновременно точно определёнными координатой и импульсом. Соотношение неопределённостей объясняет, почему для микрочастиц (в отличие от классических тел) невозможно построить точную траекторию движения — вместо этого квантовая механика описывает лишь вероятность обнаружить частицу в той или иной области пространства.",
"138": "Основные понятия: Неравновесное излучение — это электромагнитное излучение, возникающее не за счёт теплового движения атомов (как равновесное тепловое излучение), а за счёт какого-либо иного, «неравновесного» источника энергии — химической реакции, электрического разряда, поглощения света другой длины волны и т.д.; такое излучение не подчиняется законам теплового излучения и его спектр не определяется одной лишь температурой тела. Люминесценция — частный, но важный случай неравновесного излучения: свечение вещества, возникающее в результате возбуждения его атомов или молекул (за счёт поглощения света, химической реакции, электрического воздействия и др.) с последующим излучательным переходом электронов из возбуждённого состояния обратно в основное; в зависимости от источника возбуждения различают фотолюминесценцию, хемилюминесценцию, электролюминесценцию и другие виды. Люминесцентные методы широко применяются в биохимическом и медицинском анализе благодаря высокой чувствительности при обнаружении даже малых количеств определённых веществ.",
"139": "Основные понятия: Спонтанное излучение — это самопроизвольный, случайный по времени переход возбуждённого атома (молекулы) в состояние с меньшей энергией, сопровождающийся испусканием кванта света в случайном направлении и с произвольной фазой, независимо от внешних воздействий. Вынужденное (индуцированное) излучение — это переход возбуждённого атома в состояние с меньшей энергией, «спровоцированный» пролетающим мимо фотоном с подходящей энергией, при этом испущенный фотон оказывается точной копией «спровоцировавшего» его фотона — той же частоты, фазы, направления и поляризации, что и вызывает лавинообразное усиление света. Именно на явлении вынужденного излучения основана работа лазеров — приборов, генерирующих узконаправленный, строго монохроматический и когерентный пучок света очень высокой интенсивности, который находит широкое применение в хирургии, диагностике и терапии.",
"140": "Основные понятия: Атомное ядро — это центральная, чрезвычайно плотная часть атома, состоящая из положительно заряженных протонов и электронейтральных нейтронов, объединённых общим названием «нуклоны»; несмотря на исчезающе малый (по сравнению со всем атомом) размер, именно в ядре сосредоточена практически вся масса атома. Число протонов в ядре (заряд ядра) определяет химический элемент, к которому относится атом, а суммарное число нуклонов (протонов и нейтронов) определяет конкретный изотоп данного элемента — атомы одного элемента могут иметь разное число нейтронов при одинаковом числе протонов. Ядерные размеры на несколько порядков меньше размеров всего атома, но именно устройство ядра определяет явление радиоактивности и энергию, выделяющуюся при ядерных реакциях.",
"141": "Основные понятия: Дефект массы — это разница между суммарной массой отдельных, «свободных» (не связанных друг с другом) нуклонов, из которых состоит ядро, и фактической массой самого ядра — масса ядра всегда несколько меньше суммы масс составляющих его нуклонов, поскольку часть массы при их объединении в ядро «превращается» в энергию связи, удерживающую нуклоны вместе. Энергия связи ядра — это энергия, которая выделилась бы при образовании ядра из отдельных нуклонов (или, эквивалентно, энергия, которую нужно затратить, чтобы разделить ядро на отдельные нуклоны); эта эквивалентность массы и энергии описывается знаменитым соотношением Эйнштейна E=mc². Энергия связи, приходящаяся на один нуклон, характеризует прочность ядра и определяет, при каких ядерных превращениях (делении тяжёлых ядер или синтезе лёгких) выделяется энергия.",
"142": "Основные понятия: В природе существуют четыре типа фундаментальных взаимодействий: гравитационное (самое слабое, но дальнодействующее, действует между любыми массами), электромагнитное (действует между заряженными частицами, ответственно за химические связи, электрические и магнитные явления), сильное (ядерное) взаимодействие (самое мощное, но короткодействующее — эффективно только на расстояниях порядка размеров ядра) и слабое взаимодействие (ответственно, в частности, за некоторые виды радиоактивного распада). Ядерные силы (сильное взаимодействие) удерживают вместе положительно заряженные протоны в ядре, несмотря на их сильное кулоновское (электростатическое) отталкивание, потому что на малых, внутриядерных расстояниях сильное взаимодействие значительно превышает по величине электромагнитное отталкивание — но эта сила очень быстро убывает с расстоянием и практически не действует за пределами ядра.",
"143": "Основные понятия: Стабильные ядра — это ядра, которые могут существовать сколь угодно долго без самопроизвольного изменения своего состава, поскольку в них силы притяжения (ядерные силы) и отталкивания (кулоновские силы между протонами) сбалансированы оптимальным соотношением числа протонов и нейтронов. Радиоактивные (нестабильные) ядра — это ядра с «неудачным» соотношением протонов и нейтронов (слишком много или слишком мало нейтронов относительно протонов, либо избыточная масса), которые самопроизвольно, без внешнего воздействия, превращаются в другие ядра, испуская при этом ионизирующее излучение (альфа-, бета-частицы или гамма-кванты) — это явление называется радиоактивностью. Радиоактивность — вероятностный, статистический процесс: невозможно предсказать момент распада конкретного отдельного ядра, но для большого количества одинаковых ядер закономерность распада во времени строго определена.",
"144": "Основные понятия: Закон радиоактивного распада описывает, как со временем убывает число ещё не распавшихся радиоактивных ядер в образце: поскольку распад каждого отдельного ядра — случайное событие, не зависящее от «возраста» ядра и от поведения соседних ядер, число оставшихся (нераспавшихся) ядер убывает со временем по экспоненциальному закону. Физический смысл закона в том, что за равные промежутки времени распадается не одинаковое количество ядер, а одинаковая доля от оставшегося на тот момент количества ядер — поэтому скорость распада (число распадов в единицу времени) постепенно замедляется по мере уменьшения числа оставшихся радиоактивных ядер. Этот закон универсален для всех радиоактивных изотопов и отличается только характерной скоростью убывания, определяемой постоянной распада (или периодом полураспада) данного изотопа.",
"145": "Основные понятия: Активность радиоактивного источника — это число распадов атомных ядер, происходящих в образце за единицу времени; активность прямо пропорциональна количеству ещё не распавшихся радиоактивных ядер в образце и, соответственно, со временем убывает по тому же экспоненциальному закону, что и само количество радиоактивных ядер. Удельная активность — это активность, приходящаяся на единицу массы (или объёма, или числа частиц) вещества, что позволяет сравнивать «интенсивность» радиоактивности разных образцов независимо от их общей массы или объёма. Активность — практически измеримая величина (в отличие от абсолютного числа радиоактивных ядер), поэтому именно она используется на практике для характеристики радиоактивных источников, в том числе в медицине (например, при дозировании радиофармпрепаратов).",
"146": "Основные понятия: Постоянная распада — это характеристика конкретного радиоактивного изотопа, показывающая вероятность распада одного ядра данного изотопа в единицу времени; чем больше постоянная распада, тем «быстрее» (в вероятностном смысле) распадается вещество. Период полураспада — более наглядная и часто используемая на практике характеристика: это время, за которое распадается ровно половина от исходного количества радиоактивных ядер в образце (или, эквивалентно, за которое активность образца уменьшается вдвое); период полураспада обратно пропорционален постоянной распада и является строго индивидуальной характеристикой каждого изотопа, не зависящей от внешних условий (температуры, давления, химического состояния) — от долей секунды до миллиардов лет для разных изотопов.",
"147": "Основные понятия: Искусственная радиоактивность — это радиоактивность, вызванная не природными процессами, а искусственно, в результате ядерных реакций — воздействия на стабильные (в природе нерадиоактивные) ядра пучками частиц (нейтронов, протонов и др.) в ядерных реакторах или ускорителях, в результате чего образуются радиоактивные изотопы, отсутствующие или крайне редкие в природе. Ядерные реакции — это процессы взаимодействия атомных ядер друг с другом или с элементарными частицами, приводящие к изменению состава и/или энергетического состояния ядер, в отличие от радиоактивного распада, который происходит самопроизвольно, без внешнего инициирующего воздействия. Искусственно полученные радиоактивные изотопы широко применяются в медицине — как для диагностики (радиофармпрепараты для сцинтиграфии, ПЭТ), так и для лучевой терапии злокачественных новообразований.",
"148": "Основные понятия: Ионизирующее излучение — это любое излучение (электромагнитное или в виде потока частиц), способное при взаимодействии с веществом выбивать электроны из атомов и молекул, превращая их в заряженные ионы, то есть вызывать ионизацию вещества; для этого энергия отдельных квантов или частиц излучения должна превышать энергию связи электронов в атомах. Классификация ионизирующего излучения разделяет его на электромагнитное (рентгеновское и гамма-излучение — фотоны высокой энергии) и корпускулярное (потоки заряженных или незаряженных частиц: альфа-частицы, бета-частицы (электроны или позитроны), нейтроны, протоны и др.), которые существенно различаются по проникающей способности и характеру воздействия на вещество и биологические ткани.",
"149": "Основные понятия: При прохождении ионизирующего излучения через вещество происходит передача энергии излучения атомам и молекулам вещества, приводящая к разным эффектам: ионизации (выбиванию электронов из атомов с образованием ионов), возбуждению атомов и молекул (переходу электронов на более высокие энергетические уровни без полного отрыва от атома) и, в случае достаточно высоких энергий, к разрыву химических связей в молекулах, включая биологически важные молекулы (ДНК, белки). В биологических тканях, состоящих в основном из воды, ионизирующее излучение также вызывает радиолиз воды — разложение молекул воды с образованием высокореакционных свободных радикалов, которые затем химически повреждают биомолекулы клетки, что лежит в основе биологического действия радиации.",
"150": "Основные понятия: Количественные характеристики ионизирующего излучения позволяют объективно описать интенсивность и биологическую значимость облучения с разных сторон: экспозиционная доза характеризует ионизирующую способность излучения в воздухе, поглощённая доза — количество энергии излучения, поглощённой единицей массы облучаемого вещества (независимо от типа вещества), эквивалентная доза учитывает разную биологическую эффективность разных видов излучения при одинаковой поглощённой дозе, а активность источника характеризует интенсивность самого источника излучения независимо от того, что и как им облучается. Эта система взаимосвязанных, но не тождественных величин необходима потому, что разные виды излучения при одинаковой поглощённой энергии могут вызывать существенно разный по тяжести биологический эффект.",
"151": "Основные понятия: Особенность действия ионизирующего излучения на организм заключается в том, что даже сравнительно небольшая поглощённая энергия излучения способна вызвать несоразмерно тяжёлые биологические последствия — это связано не с количеством переданной телу тепловой энергии (оно, как правило, ничтожно мало), а со специфическим повреждающим действием ионизации на уровне отдельных молекул, в первую очередь на молекулы ДНК, где даже единичные повреждения могут приводить к мутациям, гибели клетки или её злокачественному перерождению. Биологическое действие ионизирующего излучения складывается из прямого действия (непосредственное повреждение критических молекул самим излучением) и косвенного, опосредованного действия через продукты радиолиза воды (свободные радикалы), составляющие большую часть повреждений в живых тканях, богатых водой.",
"152": "Основные понятия: Мишенями (критическими молекулярными структурами) действия ионизирующего излучения в клетке являются в первую очередь молекулы ДНК в ядре клетки, повреждение которых (разрывы цепей, повреждение оснований) может привести к мутациям, нарушению деления клетки или её гибели, а также молекулы белков и липидов мембран, повреждение которых нарушает структуру и функцию клеточных структур. Особая уязвимость ДНК как основной мишени радиационного повреждения связана с тем, что клетка обладает ограниченными возможностями репарации (восстановления) повреждённой ДНК, и не всегда успешно устраняет возникшие повреждения, а клетки, наиболее интенсивно делящиеся (например, клетки костного мозга, эпителия кишечника, половые клетки), особенно чувствительны к радиационному повреждению именно из-за высокой активности деления и репликации ДНК.",
"153": "Основные понятия: Доза ионизирующего излучения — это количественная мера воздействия излучения на вещество (в частности, поглощённая доза — энергия излучения, поглощённая единицей массы облучённого вещества), характеризующая суммарный эффект облучения независимо от того, за какое время эта доза была получена. Мощность дозы показывает, с какой скоростью накапливается доза облучения, то есть какая доза поглощается веществом в единицу времени; одна и та же суммарная доза, полученная за короткое время при высокой мощности дозы, как правило, приводит к более тяжёлым биологическим последствиям, чем та же доза, растянутая на длительное время при низкой мощности, поскольку организм успевает частично восстанавливать (репарировать) повреждения между отдельными актами облучения.",
"154": "Основные понятия: Экспозиционная доза — это величина, характеризующая ионизирующую способность рентгеновского и гамма-излучения именно в воздухе, определяемая как суммарный электрический заряд ионов одного знака, образованных излучением в единице массы воздуха при полном использовании ионизирующей способности излучения. Экспозиционная доза — исторически первая и наиболее просто измеримая (с помощью ионизационной камеры) характеристика излучения, но она применима только к электромагнитному излучению (рентгеновскому и гамма) и только для воздуха как среды, поэтому в современной дозиметрии она постепенно вытесняется более универсальной поглощённой дозой, применимой к любому виду излучения и любому облучаемому веществу, включая биологические ткани.",
"155": "Основные понятия: Эквивалентная доза — это величина, введённая для сравнения биологической опасности разных видов ионизирующего излучения при одной и той же поглощённой дозе: она равна поглощённой дозе, умноженной на коэффициент качества (взвешивающий коэффициент), учитывающий, что при одинаковой поглощённой энергии разные виды излучения вызывают разный по тяжести биологический эффект. Коэффициент качества отражает так называемую линейную передачу энергии излучения веществу: излучения с высокой плотностью ионизации на единицу пройденного пути (например, альфа-частицы) вызывают значительно более тяжёлые локальные повреждения тканей при той же поглощённой дозе, чем излучения с низкой плотностью ионизации (например, гамма-излучение), и поэтому имеют значительно больший коэффициент качества. Именно эквивалентная доза, а не поглощённая, лучше отражает реальный биологический риск облучения и используется в нормативах радиационной безопасности.",
"156": "Основные понятия: Безопасные уровни облучения — это установленные на основе научных данных о биологическом действии радиации значения дозы, при которых риск неблагоприятных последствий для здоровья считается пренебрежимо малым или приемлемым в конкретных условиях (для населения, для персонала, работающего с источниками излучения, при медицинских процедурах). Предельно допустимые дозы — это регламентированные (законодательно закреплённые) нормативы максимально допустимого облучения для разных категорий лиц за определённый период времени (обычно за год), установленные с существенным запасом безопасности относительно доз, при которых начинают наблюдаться доказанные вредные эффекты для здоровья. Такие нормативы необходимы для баланса между пользой от использования источников ионизирующего излучения (в медицине, промышленности, энергетике) и минимизацией связанного с ними радиационного риска для человека.",
"157": "Основные понятия: Дозы, получаемые пациентами при рентгенографии и компьютерной томографии (КТ), — это реальные значения эффективной (или эквивалентной) дозы облучения, которые пациент получает при конкретном диагностическом исследовании с использованием рентгеновского излучения; эти дозы существенно различаются в зависимости от вида исследования, обследуемой области тела и используемого оборудования. Как правило, КТ-исследования сопряжены с значительно более высокими дозами облучения по сравнению с обычной рентгенографией, поскольку компьютерная томография предполагает получение множества последовательных рентгеновских проекций (срезов) для построения объёмного изображения органа. Знание типичных диагностических доз важно для обоснованного выбора метода исследования врачом, соблюдения принципа оптимизации (получение необходимой диагностической информации при минимально возможной дозе облучения пациента) и корректного учёта суммарной лучевой нагрузки на пациента при повторных исследованиях.",
}

with open("physics_questions.json", "r", encoding="utf-8") as f:
    data = json.load(f)

changed = 0
for k, new_intro in NEW_INTRO.items():
    a = data[k]["answer"]
    parts = a.split("\n\n", 1)
    rest = parts[1] if len(parts) > 1 else ""
    if rest:
        data[k]["answer"] = new_intro + "\n\n" + rest
    else:
        data[k]["answer"] = new_intro
    changed += 1

with open("physics_questions.json", "w", encoding="utf-8") as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("changed:", changed)
